













































































import {Component, Vue} from "vue-property-decorator";

@Component
export default class FrontComponent extends Vue {

  test(): any {

    switch (this.$vuetify.breakpoint.name) {

      case 'xs': return require('@/assets/extra-small.jpg');
      case "sm": return require('@/assets/small.jpg');
      case "md": return require('@/assets/medium.jpg');
      default: return require('@/assets/wide.jpg');

    }

  }

}
