























































































import Vue from 'vue';
import FrontComponent from "@/components/FrontComponent.vue";
import ProjectsComponent from "@/components/ProjectsComponet.vue";
import AboutComponent from "@/components/AboutComponent.vue";
import {Component} from "vue-property-decorator";
import FooterComponent from "@/components/FooterComponent.vue";

@Component({
  components: {
    FooterComponent,
    ProjectsComponent,
    FrontComponent,
    AboutComponent
  }
})
export default class App extends Vue {

  private drawer = false;

  showHeader = false;

  elevation = '0';

  logoColor = 'black';
  bg = '#1d1d1d';
  headerButton = 'white';

  private mounted() {
    window.onscroll = () => {
      this.changeAppBarColor();
    }
  }

  private goto(refName: string) {
    var element = this.$refs[refName] as HTMLElement;
    var top = element.offsetTop;
    window.scrollTo(0, top);
  }


  private changeAppBarColor() {
    if (
        document.body.scrollTop > 100 ||
        document.documentElement.scrollTop > 100
    ) {
      this.bg = 'white';
      this.headerButton = 'black';
      this.elevation = '2';
    } else {
      this.bg = '#1d1d1d';
      this.headerButton = 'white';
      this.elevation = '0';
    }
  }


}
